//! Evaluation helpers for binops, function calls, and array literals.

use mlpl_array::{DenseArray, Shape};
use mlpl_parser::{BinOpKind, Expr};
use mlpl_trace::{Trace, TraceValue};

use crate::env::Environment;
use crate::error::EvalError;
use crate::eval::eval_expr;
use crate::value::Value;

pub(crate) fn eval_binop(
    op: &BinOpKind,
    lhs: &Expr,
    rhs: &Expr,
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
    let l = eval_expr(lhs, env, trace)?.into_array()?;
    let r = eval_expr(rhs, env, trace)?.into_array()?;
    let (name, f): (&str, fn(f64, f64) -> f64) = match op {
        BinOpKind::Add => ("add", |a, b| a + b),
        BinOpKind::Sub => ("sub", |a, b| a - b),
        BinOpKind::Mul => ("mul", |a, b| a * b),
        BinOpKind::Div => ("div", |a, b| a / b),
    };
    let inputs = vec![TraceValue::from_array(&l), TraceValue::from_array(&r)];
    let result = l.apply_binop(&r, f)?;
    Ok((name, inputs, result))
}

pub(crate) fn eval_fncall(
    name: &str,
    args: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
    let evaluated: Vec<DenseArray> = args
        .iter()
        .map(|a| eval_expr(a, env, trace).and_then(Value::into_array))
        .collect::<Result<Vec<_>, _>>()?;
    let inputs: Vec<TraceValue> = evaluated.iter().map(TraceValue::from_array).collect();
    let result = mlpl_runtime::call_builtin(name, evaluated)?;
    Ok(("fncall", inputs, result))
}

pub(crate) fn eval_svg(
    args: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<String, EvalError> {
    if args.len() != 2 {
        return Err(EvalError::BadArity {
            func: "svg".into(),
            expected: 2,
            got: args.len(),
        });
    }
    let data = eval_expr(&args[0], env, trace)?.into_array()?;
    let type_name = match eval_expr(&args[1], env, trace)? {
        Value::Str(s) => s,
        Value::Array(_) => return Err(EvalError::ExpectedString),
    };
    Ok(mlpl_viz::render(&data, &type_name)?)
}

pub(crate) fn eval_array_lit(
    elems: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<DenseArray, EvalError> {
    if elems.is_empty() {
        return Ok(DenseArray::from_vec(vec![]));
    }
    let evaluated: Vec<DenseArray> = elems
        .iter()
        .map(|e| eval_expr(e, env, trace).and_then(Value::into_array))
        .collect::<Result<Vec<_>, _>>()?;
    if evaluated.iter().all(|a| a.rank() == 0) {
        let data: Vec<f64> = evaluated.iter().map(|a| a.data()[0]).collect();
        return Ok(DenseArray::from_vec(data));
    }
    let inner_shape = evaluated[0].shape().clone();
    let rows = evaluated.len();
    let mut data = Vec::with_capacity(rows * inner_shape.elem_count());
    for arr in &evaluated {
        data.extend_from_slice(arr.data());
    }
    let mut dims = vec![rows];
    dims.extend_from_slice(inner_shape.dims());
    Ok(DenseArray::new(Shape::new(dims), data)?)
}

//! Built-in function implementations.

use mlpl_array::{DenseArray, Shape};

use crate::error::RuntimeError;
use crate::math_builtins;

macro_rules! check_arity {
    ($name:expr, $expected:expr, $args:expr) => {
        if $args.len() != $expected {
            return Err(RuntimeError::ArityMismatch {
                func: $name.into(),
                expected: $expected,
                got: $args.len(),
            });
        }
    };
}

/// Dispatch a built-in function call by name.
pub fn call_builtin(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    // Try math/constructor builtins first
    if let Some(result) = math_builtins::try_call(name, args.clone()) {
        return result;
    }
    match name {
        "iota" => builtin_iota(name, args),
        "shape" => builtin_shape(name, args),
        "rank" => builtin_rank(name, args),
        "reshape" => builtin_reshape(name, args),
        "transpose" => builtin_transpose(name, args),
        "reduce_add" | "reduce_mul" => builtin_reduce(name, args),
        "dot" => {
            check_arity!(name, 2, args);
            Ok(args[0].dot(&args[1])?)
        }
        "matmul" => {
            check_arity!(name, 2, args);
            Ok(args[0].matmul(&args[1])?)
        }
        _ => Err(RuntimeError::UnknownFunction(name.into())),
    }
}

fn builtin_iota(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    if args[0].rank() != 0 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: format!("expected scalar, got rank {}", args[0].rank()),
        });
    }
    let n = args[0].data()[0] as usize;
    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
    Ok(DenseArray::from_vec(data))
}

fn builtin_shape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    let dims: Vec<f64> = args[0].shape().dims().iter().map(|&d| d as f64).collect();
    Ok(DenseArray::from_vec(dims))
}

fn builtin_rank(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(DenseArray::from_scalar(args[0].rank() as f64))
}

fn builtin_reshape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 2, args);
    let shape_data = args[1].data();
    let dims: Vec<usize> = shape_data.iter().map(|&d| d as usize).collect();
    Ok(args[0].reshape(Shape::new(dims))?)
}

fn builtin_transpose(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(args[0].transpose())
}

fn builtin_reduce(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if args.len() != 1 && args.len() != 2 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 1,
            got: args.len(),
        });
    }
    let (identity, op): (f64, fn(f64, f64) -> f64) = match name {
        "reduce_add" => (0.0, |a, b| a + b),
        "reduce_mul" => (1.0, |a, b| a * b),
        _ => unreachable!(),
    };
    if args.len() == 2 {
        if args[1].rank() != 0 {
            return Err(RuntimeError::InvalidArgument {
                func: name.into(),
                reason: format!("axis must be scalar, got rank {}", args[1].rank()),
            });
        }
        let axis = args[1].data()[0] as usize;
        Ok(args[0].reduce_axis(axis, identity, op)?)
    } else {
        let result = args[0].data().iter().copied().fold(identity, op);
        Ok(DenseArray::from_scalar(result))
    }
}

